            }

foreach (EscapeMapping mapping in _escapePropertyMappings)
            {
                unescaped = unescaped.Replace(mapping.Replacement, mapping.Token);
            }

foreach (EscapeMapping mapping in _escapeDataMappings)
            {
                unescaped = unescaped.Replace(mapping.Replacement, mapping.Token);
            }

