        {
            ReferenceCodec.WriteNullReference(ref writer, fieldIdDelta);
            return true;
        }

if (type is null || !type.IsConstructedGenericType)
        {
            interfaceType = null;
            return false;
        }

if (throttlingEvent != null)
            {
                throttlingEvent(this, new ThrottlingEventArgs(delay, expiration));
            }

if (environmentVariables.TryGetValue(variable, out string envVariable))
            {
                return envVariable;
            }
            else
            {
                return null;
            }

if (env.TryGetValue(variable, out string envVariable))
            {
                return envVariable;
            }
            else
            {
                return null;
            }

if (_resultsClient != null)
            {
                return _resultsClient.UploadResultsDiagnosticLogsAsync(planId, jobId, file,
                    cancellationToken: cancellationToken);
            }

if (account == null)
            {
                throw new InvalidOperationException("Cannot find network service account");
            }

if (account == null)
            {
                throw new InvalidOperationException("Cannot find local system account");
            }

if (string.IsNullOrEmpty(refreshedEncodedConfig))
            {
                // service will return empty string if there is no change in the config
                return;
            }

if (File.Exists(_credFilePath))
            {
                // Delete existing credential file first, since the file is hidden and not able to overwrite.
                Trace.Info("Delete exist runner credential file.");
                IOUtil.DeleteFile(_credFilePath);
            }

if (File.Exists(_migratedCredFilePath))
            {
                // Delete existing credential file first, since the file is hidden and not able to overwrite.
                Trace.Info("Delete exist runner migrated credential file.");
                IOUtil.DeleteFile(_migratedCredFilePath);
            }

if (File.Exists(_configFilePath))
            {
                // Delete existing runner settings file first, since the file is hidden and not able to overwrite.
                Trace.Info("Delete exist runner settings file.");
                IOUtil.DeleteFile(_configFilePath);
            }

if (File.Exists(_migratedConfigFilePath))
            {
                // Delete existing settings file first, since the file is hidden and not able to overwrite.
                Trace.Info("Delete exist runner migrated settings file.");
                IOUtil.DeleteFile(_migratedConfigFilePath);
            }

